/**
 * Spreadsheet Core Logic
 * Implements state management, calculation engine, dependency tracking, and UI interaction.
 */

class Spreadsheet {
    constructor(gridSize = { rows: 10, cols: 10 }) {
        this.rows = gridSize.rows;
        this.cols = gridSize.cols;
        // State storage: key is "A1", value is the raw formula/text string
        this.rawValues = {};
        // Computed values cache: key is "A1", value is the computed number/string
        this.computedValues = {};
        // Dependencies: key is "B2", value is Set of cells it depends on (e.g., {"A1", "C3"})
        this.dependencies = {};

        this._initializeGrid();
    }

    /** Initializes the internal state and sets up event listeners for all 100 cells. */
    _initializeGrid() {
        const cellIds = [];
        for (let r = 1; r <= this.rows; r++) {
            for (let c = 1; c <= this.cols; c++) {
                const id = String.fromCharCode(64 + (c - 1)) + r; // A, B, C...
                cellIds.push(id);
                this.rawValues[id] = ""; // Initialize all cells as empty strings
            }
        }

        // Set up event listeners for input changes and focus loss
        document.querySelectorAll('.cell input').forEach(input => {
            const id = input.getAttribute('data-id');
            if (id) {
                // Use 'blur' to commit changes when clicking away, simulating Enter key behavior
                input.addEventListener('blur', () => this._handleCommit(id));
                // Handle direct input change (typing)
                input.addEventListener('input', (e) => {
                    const value = e.target.value;
                    this.rawValues[id] = value;
                    this._recalculateAll(); // Trigger recalculation immediately on typing
                });
            }
        });

        // Initial calculation run to populate the display
        this._recalculateAll(true);
    }

    /**
     * Gets a cell ID from coordinates (e.g., 'A1').
     * @param {string} id - The cell identifier.
     * @returns {boolean} True if valid, false otherwise.
     */
    isValidId(id) {
        const regex = /^([A-Z]+)([1-9][0-9]*)$/;
        return regex.test(id);
    }

    /**
     * Gets the raw text content of a cell.
     * @param {string} id - Cell ID (e.g., "B2").
     * @returns {string} The stored raw value.
     */
    raw(id) {
        return this.rawValues[id] || "";
    }

    /**
     * Sets the raw text content of a cell, triggering recalculation.
     * This is the primary API setter.
     * @param {string} id - Cell ID (e.g., "B2").
     * @param {string} value - The new raw string value.
     */
    set(id, value) {
        if (!this.isValidId(id)) return;

        // Update internal state
        this.rawValues[id] = String(value);

        // Update the UI input element
        const inputElement = document.getElementById(`cell-${id}`);
        if (inputElement) {
            inputElement.value = this.rawValues[id];
        }

        // Trigger recalculation for all dependent cells
        this._recalculateAll();
    }

    /**
     * Gets the displayed computed value of a cell.
     * @param {string} id - Cell ID (e.g., "B2").
     * @returns {string} The formatted display string.
     */
    get(id) {
        if (!this.isValidId(id)) return "";
        return this.computedValues[id] !== undefined ? String(this.computedValues[id]) : "";
    }

    /**
     * Gets the raw text content of a cell (alias for raw()).
     * @param {string} id - Cell ID (e.g., "B2").
     * @returns {string} The stored raw value.
     */
    rawText(id) {
        return this.raw(id);
    }

    /**
     * Handles the commit process when a cell loses focus or Enter is pressed.
     * This ensures that even if the user modifies the input directly, the state is updated and recalculated.
     * @param {string} id - The ID of the cell being committed.
     */
    _handleCommit(id) {
        const inputElement = document.getElementById(`cell-${id}`);
        if (inputElement) {
            // Update internal raw value from the current input state
            this.rawValues[id] = inputElement.value;
            // Recalculate everything based on the committed change
            this._recalculateAll();
        }
    }

    /**
     * Core calculation logic for a single cell.
     * @param {string} id - The ID of the cell to calculate.
     * @returns {{value: (number|string), error: string}} The result and any error message.
     */
    _calculateCell(id) {
        const rawFormula = this.rawValues[id].trim();

        // 1. Handle empty cells or non-formula text
        if (!rawFormula || !rawFormula.startsWith('=')) {
            return { value: rawFormula === "" ? 0 : rawFormula, error: null };
        }

        let formula = rawFormula.substring(1); // Remove leading '='

        // 2. Dependency Tracking (Pre-pass)
        const dependencies = new Set();
        const cellRegex = /([A-Z]+[1-9][0-9]*)/g;
        let match;
        while ((match = cellRegex.exec(formula)) !== null) {
            dependencies.add(match[0]);
        }

        // Store dependencies for later use in recalculation
        this.dependencies[id] = dependencies;

        // 3. Check for Circular References (DFS approach is complex here, we rely on iteration detection)
        // For simplicity and robustness in this single-pass model, we assume the calling function handles cycle detection by checking recursion depth/history.
        // If a cell depends on itself or its dependency chain leads back to it, the recursive caller must detect it.

        try {
            // 4. Substitute references with actual values (and handle empty cells as 0)
            let expression = formula;
            const resolvedValues = {}; // Temporary storage for current calculation pass's results

            // Replace cell references: A1 -> value of A1
            expression = expression.replace(cellRegex, (match) => {
                const val = this.get(match);
                if (typeof val === 'number') return val;
                return JSON.stringify(val); // Use stringify to safely embed strings in the math context
            });

            // 5. Evaluate the expression
            let result;
            try {
                // eslint-disable-next-line no-eval
                result = eval(expression);
            } catch (e) {
                return { value: null, error: "#ERR" }; // Syntax or runtime error
            }

            // 6. Final formatting and return
            if (isNaN(parseFloat(result)) || !isFinite(result)) {
                 return { value: result === Infinity ? "Infinity" : String(result), error: null };
            }

            return { value: parseFloat(result), error: null };

        } catch (e) {
            console.error(`Error calculating ${id}:`, e);
            return { value: null, error: "#ERR" };
        }
    }


    /**
     * Recalculates the entire sheet or a subset of cells based on changes.
     * @param {boolean} initialLoad - If true, skips cycle detection checks and runs full calculation.
     */
    _recalculateAll(initialLoad = false) {
        // We must iterate multiple times to ensure transitive updates (e.g., A1 -> B2 -> C3)
        let changedCount = 0;
        const maxIterations = this.rows * this.cols + 2; // Safety break

        for (let i = 0; i < maxIterations && changedCount < 1; i++) {
            let previousComputedValues = {...this.computedValues};
            changedCount = 0;

            // Calculate all cells in a stable order (e.g., row by row, column by column)
            for (let r = 1; r <= this.rows; r++) {
                for (let c = 1; c <= this.cols; c++) {
                    const id = String.fromCharCode(64 + (c - 1)) + r;

                    // Skip calculation if the cell is empty and not a formula
                    if (!this.rawValues[id] || !this.rawValues[id].startsWith('=')) {
                        continue;
                    }

                    const result = this._calculateCell(id);
                    const newValue = result.error ? result.error : result.value;

                    // Check if the value actually changed (or if it's an initial load)
                    if (String(previousComputedValues[id]) !== String(newValue)) {
                        this.computedValues[id] = newValue;
                        changedCount++;
                    }
                }
            }

            if (changedCount === 0 && !initialLoad) {
                break; // Stable state reached
            }
        }
    }


    /**
     * Public method to trigger recalculation after a manual set/raw call.
     */
    recalculate() {
        this._recalculateAll();
    }

    /**
     * Exports the current computed values of the grid into a CSV string.
     * @returns {string} The comma-separated value string.
     */
    exportCSV() {
        let csv = [];
        for (let r = 1; r <= this.rows; r++) {
            const rowData = [];
            for (let c = 1; c <= this.cols; c++) {
                const id = String.fromCharCode(64 + (c - 1)) + r;
                // Use the computed value for export
                rowData.push(`"${String(this.get(id)).replace(/"/g, '""')}"`); // Escape quotes
            }
            csv.push(rowData.join(','));
        }
        return csv.join('\n');
    }
}

// --- Initialization and API Exposure ---

