    set: (id, value) => sheet.set(id, value),
    get: (id) => sheet.get(id),
    raw: (id) => sheet.rawText(id)
};


// --- Event Listeners for Export Button ---

document.getElementById('export').addEventListener('click', () => {
    const csvOutput = document.getElementById('csv');
    csvOutput.value = sheet.exportCSV();
});

</script>

